import org.elasticsearch.action.admin.indices.create.CreateIndexRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/products")
@SpringBootApplication
public class ProductSearchEngine {

    @Autowired
    private RestHighLevelClient restHighLevelClient;

    public static void main(String[] args) {
        SpringApplication.run(ProductSearchEngine.class, args);
    }

    // Create an index for products in Elasticsearch if it doesn't exist already
    @PostMapping("/createIndex")
    public String createIndex() throws IOException {
        boolean exists = restHighLevelClient.indices().exists("products");
        if (!exists) {
            CreateIndexRequest createIndexRequest = new CreateIndexRequest("products");
            restHighLevelClient.indices().create(createIndexRequest, RequestOptions.DEFAULT);
        }
        return "Products index created";
    }

    // Index a product in Elasticsearch
    @PostMapping("/index")
    public String index(@RequestBody Product product) throws IOException {
        Map<String, Object> jsonMap = new HashMap<>();
        jsonMap.put("name", product.getName());
        jsonMap.put("description", product.getDescription());
        jsonMap.put("price", product.getPrice());

        IndexRequest indexRequest = new IndexRequest("products")
                .source(jsonMap);

        restHighLevelClient.index(indexRequest, RequestOptions.DEFAULT);

        return "Product added to the index";
    }
}